18	// US-037 — lister profile. Renders org_name (from lister_profiles),
19	// email + username (from users via AuthContext), and a canonical sign-out
20	// button. Sign-out clears the persisted JWT via AuthProvider.signOut,
21	// which triggers the role-based router at app/index.tsx to drop the user
22	// back into the (auth) group.
23	
24	type ListerProfileRow = Database['public']['Tables']['lister_profiles']['Row'];
25	
26	export default function ListerProfile() {
27	  const { user, signOut } = useAuth();
28	  const { show: showToast } = useToast();
29	
30	  const [profile, setProfile] = useState<ListerProfileRow | null>(null);
31	  const [loading, setLoading] = useState(true);
32	
33	  const load = useCallback(async () => {
34	    if (!user) return;
35	    setLoading(true);
36	    try {
37	      const { data, error } = await supabase
38	        .from('lister_profiles')
39	        .select('*')
40	        .eq('user_id', user.id)
41	        .maybeSingle();
42	      if (error) throw error;
43	      setProfile(data ?? null);
44	    } catch (err) {
45	      console.error('Lister profile load failed', err);
46	      showToast({ message: 'Could not load profile.', variant: 'error' });
47	    } finally {
48	      setLoading(false);
49	    }
50	  }, [user, showToast]);
51	
52	  useEffect(() => {
53	    void load();
54	  }, [load]);
55	
56	  return (
57	    <SafeAreaView style={styles.container}>
58	      <ScrollView contentContainerStyle={styles.scrollContent}>
59	        <View style={styles.header}>
60	          <Text style={[textStyles.display, { color: colors.ink }]}>Profile</Text>
61	          {user ? (
62	            <Text style={[textStyles.mono, styles.usernameRow]}>@{user.username}</Text>
63	          ) : null}
64	        </View>
65	
66	        {loading && profile === null ? (
67	          <View style={styles.loadingBlock}>
68	            <ActivityIndicator color={colors.ink} />
69	          </View>
70	        ) : (
71	          <View style={styles.card} testID="lister-company-card">
72	            <Text style={[textStyles.h2, { color: colors.ink }]}>Company</Text>
73	            <DetailRow label="Organization" value={profile?.org_name ?? null} />
74	            <DetailRow label="Email" value={user?.email ?? null} />
75	          </View>
76	        )}
77	
78	        <View style={styles.signOutWrap}>
79	          <ButtonSecondary
80	            label="Sign out"
81	            onPress={signOut}
82	            accessibilityLabel="Sign out"
83	            testID="lister-signout"
84	          />
85	        </View>
86	      </ScrollView>
87	    </SafeAreaView>
88	  );
89	}
90	
91	function DetailRow({ label, value }: { label: string; value: string | null }) {
92	  return (
93	    <View style={styles.detailRow}>
94	      <Text style={[textStyles.caption, { color: colors.ink70 }]}>{label}</Text>
95	      <Text style={[textStyles.body, { color: colors.ink }]}>{value ?? '—'}</Text>
96	    </View>
97	  );
98	}
99	
